<?php
declare(strict_types=1);require __DIR__.'/../includes/bootstrap.php';require_role('admin');$page_title='Attendance Records - SMIS';$rows=db_all('SELECT a.attendance_date,u.name student,s.student_number,c.name class_name,m.code,lu.name lecturer,a.status,a.remarks FROM attendance a JOIN students s ON s.id=a.student_id JOIN users u ON u.id=s.user_id JOIN classes c ON c.id=a.class_id JOIN modules m ON m.id=a.module_id JOIN lecturers l ON l.id=a.lecturer_id JOIN users lu ON lu.id=l.user_id ORDER BY a.attendance_date DESC,u.name');include __DIR__.'/../includes/header.php';?><div class="page-header"><h1>Attendance Records</h1><p>Institution-wide attendance uploaded by lecturers.</p></div><div class="card"><div class="card-body"><table class="table"><thead><tr><th>Date</th><th>Student</th><th>Class</th><th>Module</th><th>Lecturer</th><th>Status</th><th>Remarks</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=format_date($r['attendance_date'])?></td><td><strong><?=e($r['student'])?></strong><br><small><?=e($r['student_number'])?></small></td><td><?=e($r['class_name'])?></td><td><?=e($r['code'])?></td><td><?=e($r['lecturer'])?></td><td><?=status_badge($r['status'])?></td><td><?=e($r['remarks']??'-')?></td></tr><?php endforeach?></tbody></table></div></div><?php include __DIR__.'/../includes/footer.php';?>
